def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Validate that expr is a string
        if not isinstance(expr, str):
            return ""

        # Strip whitespace
        expr = expr.strip()

        # Check if expression is empty
        if not expr:
            return ""

        # Only allow safe characters: digits, operators, parentheses, decimal point, and whitespace
        allowed_chars = set("0123456789+-*/.() \t\n")
        if not all(c in allowed_chars for c in expr):
            return ""

        # Prevent multiple operators in a row (basic validation)
        # This helps prevent some invalid expressions
        import re
        # Check for invalid patterns like "++", "**", etc.
        if re.search(r'[+\-*/]{2,}', expr):
            return ""

        # Use ast.literal_eval with a restricted namespace for safety
        # Actually, we should use a safer approach with ast parsing
        import ast
        import operator

        # Parse the expression into an AST
        try:
            tree = ast.parse(expr, mode='eval')
        except SyntaxError:
            return ""

        # Validate that the AST only contains safe node types
        safe_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python < 3.8 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, safe_node_types):
                return False
            if isinstance(node, (ast.BinOp, ast.UnaryOp)):
                if isinstance(node, ast.BinOp):
                    return validate_node(node.left) and validate_node(node.right)
                else:
                    return validate_node(node.operand)
            return True

        if not validate_node(tree.body):
            return ""

        # Define safe operators
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def evaluate(node):
            if isinstance(node, ast.Expression):
                return evaluate(node.body)
            elif isinstance(node, ast.Constant):
                # Python 3.8+
                return node.value
            elif isinstance(node, ast.Num):
                # Python < 3.8
                return node.n
            elif isinstance(node, ast.BinOp):
                left = evaluate(node.left)
                right = evaluate(node.right)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operator")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = evaluate(node.operand)
                op = ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operator")
                return op(operand)
            else:
                raise ValueError("Unsupported node type")

        result = evaluate(tree)

        # Convert result to string
        if isinstance(result, float):
            # Handle float representation
            if result.is_integer():
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except (ValueError, TypeError, ZeroDivisionError, OverflowError, AttributeError):
        return ""
    except Exception:
        return ""

